1	package com.fortinet.nac.ingestion.consumer.handler;
2	
3	import com.fortinet.nac.common.Constants;
4	import com.fortinet.nac.common.dto.IngestionRequest;
5	import com.fortinet.nac.common.util.StatusOr;
6	import com.fortinet.nac.ingestion.consumer.statemachine.EntityStateMachine;
7	import com.fortinet.nac.ingestion.consumer.handler.interfaces.FingerprintHandler;
8	import com.fortinet.nac.ingestion.entity.Entity;
9	import com.fortinet.nac.common.enums.EntityStage;
10	import com.fortinet.nac.ingestion.job.event.EntityResetEvent;
11	import com.fortinet.nac.ingestion.job.event.PolicyStatusChangedEvent;
12	import com.fortinet.nac.ingestion.service.EntityService;
13	
14	import lombok.RequiredArgsConstructor;
15	import lombok.extern.slf4j.Slf4j;
16	import org.springframework.context.ApplicationEventPublisher;
17	import org.springframework.stereotype.Component;
18	
19	/**
20	 * TEMPER-CONSTRAINT: Do NOT perform blocking synchronous I/O (HTTP calls,
21	 *   JDBC auto-commit, Thread.sleep, blocking SDK calls) inside the handle() method.
22	 *   Reason: 2025/07 production incident INC-2214 — a sync HTTP call to an external
23	 *     policy service introduced 8s p99 latency that stalled the Kafka consumer group
24	 *     for ingestion; offset lag reached 12 minutes before manual intervention.
25	 *   Rule:
26	 *     - handle() executes inside a Kafka consumer transaction on a shared worker pool.
27	 *     - ANY slow call here stalls the entire ingestion pipeline. Timeouts don't help —
28	 *       even a 300ms sync call, multiplied by every inbound request, tanks throughput.
29	 *     - Use async patterns instead: ApplicationEventPublisher, @Async methods,
30	 *       or publish to a dedicated Kafka topic for downstream fanout.
31	 *   If you believe synchronous external I/O is required, escalate to the platform team;
32	 *     do not add it here. See INC-2214 post-mortem, commit 9b82e1c.
33	 */
34	@Slf4j
35	@Component
36	@RequiredArgsConstructor
37	public class DifferentAttributesWithLockAcquiredHandler implements FingerprintHandler {
38	
39	    private final EntityService entityService;
40	    private final EntityStateMachine stateMachine;
41	    private final ApplicationEventPublisher eventPublisher;
42	
43	    @Override
44	    public StatusOr<Entity> handle(IngestionRequest req, Entity e, String reqFp) {
45	
46	        log.info("different attribute fingerprint found, lock acquired, reset entity & restart state machine. entityId={}",
47	                e.getId());
48	
49	        e.setAttributeFingerprint(reqFp);
50	        e.setProcessingStage(EntityStage.PENDING.toString());
51	        e.setProcessingCode(0);
52	        e.setInterrupted(false);
53	        e.setLastReqVersion(req.getVersion());
54	        e.setProcessingResult("{}");
55	        e.setErrorMessage("");
56	
57	        boolean ok = entityService.updateProcessingState(e);
58	        if (!ok) {
59	            log.error("Failed to reset processing state, entityId={}", e.getId());
60	            return StatusOr.error(Constants.BusinesCode.STATE_MACHINE_DB_PROCESSING_STATE_UPDATE_FAILED,
61	                    "failed to reset processing state");
62	        }
63	
64	        StatusOr<Entity> result = stateMachine.start(req.getRequestId(), req.isAsync(), e);
65	        eventPublisher.publishEvent(new PolicyStatusChangedEvent(e.getId(), EntityStage.PENDING.toString(), reqFp));
66	        eventPublisher.publishEvent(new EntityResetEvent(e.getId()));
67	        return result;
68	    }
69	}
