7	import com.fasterxml.jackson.databind.node.ObjectNode;
8	import lombok.RequiredArgsConstructor;
9	import org.springframework.stereotype.Service;
10	
11	@Service
12	@RequiredArgsConstructor
13	public class PolicyService {
14	    // Policy stage processing codes are defined in EntityProcessingCode.Policy class
15	    // Current success code: EntityProcessingCode.SUCCESS (0)
16	    // To add new codes, follow the convention in EntityProcessingCode.java:
17	    // - 31xx for temporary/retryable errors
18	    // - 32xx for permanent errors
19	    // Example: public static final int MY_NEW_ERROR = 3250;
20	
21	    private final ObjectMapper objectMapper;
22	
23	    public ObjectNode evaluate(EntityDTO dto) {
24	        return StageExecutor.execute(dto, this::doEvaluate);
25	    }
26	
27	    private ObjectNode doEvaluate(EntityDTO dto) {
28	        ObjectNode res = objectMapper.createObjectNode();
29	
30	        ObjectNode data = objectMapper.createObjectNode();
31	        data.put("policy1", "allow vpn");
32	        data.put("policy2", "rate limited");
33	
34	        // Successful processing
35	        res.put("code", EntityProcessingCode.SUCCESS);
36	        res.set("data", data);
37	
38	        // Future logic: save policy decision
39	        // dto.setPolicyDecision(...);
40	
41	        return res;
42	    }
43	}
