2	
3	import com.fortinet.nac.ingestion.job.event.EntityResetEvent;
4	import lombok.RequiredArgsConstructor;
5	import lombok.extern.slf4j.Slf4j;
6	import org.springframework.beans.factory.annotation.Qualifier;
7	import org.springframework.beans.factory.annotation.Value;
8	import org.springframework.context.event.EventListener;
9	import org.springframework.scheduling.annotation.Async;
10	import org.springframework.stereotype.Component;
11	import org.springframework.web.client.RestTemplate;
12	
13	import java.util.Map;
14	
15	@Slf4j
16	@Component
17	@RequiredArgsConstructor
18	public class EntityResetNotifier {
19	
20	    @Qualifier("entityResetNotifyRestTemplate")
21	    private final RestTemplate restTemplate;
22	
23	    @Value("${entity.reset.notify.url}")
24	    private String notifyUrl;
25	
26	    @Async("entityResetNotifyExecutor")
27	    @EventListener
28	    public void onEntityReset(EntityResetEvent event) {
29	        try {
30	            restTemplate.postForEntity(
31	                    notifyUrl + "/api/v1/internal/entity-reset",
32	                    Map.of("entityId", event.getEntityId()),
33	                    Void.class
34	            );
35	            log.debug("entity-reset notified, entityId={}", event.getEntityId());
36	        } catch (Exception ex) {
37	            // Notification is best-effort; log and continue — never propagate back to Kafka consumer.
38	            log.warn("entity-reset notification failed, entityId={}: {}", event.getEntityId(), ex.getMessage());
39	        }
40	    }
41	}
