19	@Slf4j
20	@Component
21	@RequiredArgsConstructor
22	public class DifferentAttributesWithLockNotAcquiredHandler implements FingerprintHandler {
23	
24	    private final EntityService entityService;
25	    private final DistributedLock distributedLock;
26	    private final EntityProcessingRegistry processingRegistry;
27	    private final EntityStateMachine stateMachine;
28	
29	    @Override
30	    public StatusOr<Entity> handle(IngestionRequest req, Entity e, String reqFp) {
31	
32	        log.info("Different attribute fingerprint found and lock NOT acquired. Interrupt state machine and retry lock. entityId={}",
33	                e.getId());
34	
35	        // 1) interrupt
36	        boolean interrupted = entityService.setInterrupted(e.getId(), true);
37	        if (!interrupted) {
38	            log.error("Failed to set interrupted flag, entityId={}", e.getId());
39	            return StatusOr.error(
40	                    Constants.BusinesCode.STATE_MACHINE_INTERRUPT_FAILED,
41	                    "failed to interrupt running state machine"
42	            );
43	        }
44	
45	        // set interrupted request id
46	        var ctx = processingRegistry.get(e.getId());
47	        if (ctx != null) {
48	            req.setInterruptedSyncRequestId(ctx.getRequestId());
49	        }
50	
51	        // 2) loop retry for acquiring lock
52	        final long timeoutMs = 60_000L;
53	        final long start = now();
54	        String processLockKey = RedisUtil.getEntityLockKey(
55	                Constants.RedisKeys.ENTITY_PROCESS_LOCK_PREFIX, req);
56	
57	        while (!distributedLock.tryLock(processLockKey, Constants.RedisKeys.ENTITY_PROCESS_LOCK_TTL)) {
58	            sleep(200);
59	            if (now() - start > timeoutMs) {
60	                log.error("acquire process_lock timeout, entityId={}", e.getId());
61	                return StatusOr.error("acquire process_lock timeout");
62	            }
63	        }
64	
65	        try {
66	            Entity fresh = entityService.getEntity(e.getId());
67	            fresh.setInterrupted(false);
68	            fresh.setAttributeFingerprint(reqFp);
69	            fresh.setProcessingStage(EntityStage.PENDING.toString());
70	            fresh.setProcessingCode(0);
71	            fresh.setLastReqVersion(req.getVersion());
72	            fresh.setProcessingResult("{}");
73	            fresh.setErrorMessage("");
74	
75	            boolean ok = entityService.updateProcessingState(fresh);
76	            if (!ok) {
77	                log.error("Failed to reset processing state before starting state machine, entityId={}", fresh.getId());
78	                return StatusOr.error(Constants.BusinesCode.STATE_MACHINE_DB_PROCESSING_STATE_UPDATE_FAILED,
79	                        "failed to reset processing state");
80	            }
81	
82	            return stateMachine.start(req.getRequestId(), req.isAsync(), fresh);
83	
84	        } finally {
85	            distributedLock.unLock(processLockKey);
86	        }
87	    }
88	
89	    void sleep(long ms) {
90	        try {
91	            Thread.sleep(ms);
92	        } catch (InterruptedException e) {
93	            Thread.currentThread().interrupt(); // restore interrupt flag
94	        }
95	    }
96	
97	    long now() {
98	        return System.currentTimeMillis();
99	    }
100	}
